@function -zf-get-bp-val($map, $value) {
  // If the given map is a single value, return it
  @if type-of($map) == 'number' {
    @return $map;
  }


  // Check if the breakpoint name exists globally
  @if not map-has-key($breakpoints, $value) {
    @if type-of($value) == 'number' {
      $value: -zf-closest-named-breakpoint($value);
    } @else {
      @return null;
    }
  }
  // Check if the breakpoint name exists in the local config map
  @else if map-has-key($map, $value) {
    // If it does, just return the value
    @return map-get($map, $value);
  }
  // Otherwise, find the next lowest breakpoint and return that value
  @else {
    $anchor: null;
    $found: false;

    @each $key, $val in $breakpoints {
      @if not $found {
        @if map-has-key($map, $key) {
          $anchor: $key;
        }
        @if $key == $value {
          $found: true;
        }
      }
    }

    @return map-get($map, $anchor);
  }
}

@mixin v1-generate-on-scheme-colors($name, $base, $scheme-main) {
  // Accessibility Contrast System
  $scheme-main-brightness: fn.bulmaColorBrightness($scheme-main);
  $on-scheme-color: $base;

  @if ($scheme-main-brightness == "bright") {
    @while (fn.bulmaEnoughContrast($on-scheme-color, #fff) == false) {
      // We're on a light background, so we'll darken the test color step by step.
      $on-scheme-color: color.adjust(
        $on-scheme-color,
        $lightness: -5%,
        $space: hsl
      );
    }
  } @else {
    @while (fn.bulmaEnoughContrast($on-scheme-color, #000) == false) {
      // We're on a dark background, so we'll lighten the test color step by step.
      $on-scheme-color: color.adjust(
        $on-scheme-color,
        $lightness: 5%,
        $space: hsl
      );
    }
  }

  $on-scheme-lightness: color.channel(
    $on-scheme-color,
    "lightness",
    $space: hsl
  );
  @include register-var($name, $on-scheme-lightness, "", "-on-scheme-l");
}

@mixin _directional-property(
  $property,
  $suffix,
  $values
) {
  $top: $property + "-top" + if($suffix, "-#{$suffix}", "");
  $bottom: $property + "-bottom" + if($suffix, "-#{$suffix}", "");
  $left: $property + "-left" + if($suffix, "-#{$suffix}", "");
  $right: $property + "-right" + if($suffix, "-#{$suffix}", "");
  $all: $property + if($suffix, "-#{$suffix}", "");

  $values: _compact-shorthand($values);

  @if _contains-falsy($values) {
    @if nth($values, 1) { #{$top}: nth($values, 1); }

    @if length($values) == 1 {
      @if nth($values, 1) { #{$right}: nth($values, 1); }
    } @else {
      @if nth($values, 2) { #{$right}: nth($values, 2); }
    }

    @if length($values) == 2 {
      @if nth($values, 1) { #{$bottom}: nth($values, 1); }
      @if nth($values, 2) { #{$left}: nth($values, 2); }
    } @else if length($values) == 3 {
      @if nth($values, 3) { #{$bottom}: nth($values, 3); }
      @if nth($values, 2) { #{$left}: nth($values, 2); }
    } @else if length($values) == 4 {
      @if nth($values, 3) { #{$bottom}: nth($values, 3); }
      @if nth($values, 4) { #{$left}: nth($values, 4); }
    }
  } @else {
    #{$all}: $values;
  }
}

@mixin foundation-flex-classes {
  // Horizontal alignment using justify-content
  @each $hdir, $prop in $-zf-flex-justify {
    .align-#{$hdir} {
      @include flex-align($x: $hdir);
    }
  }

  // Horizontal alignment Specifically for Vertical Menu
  @each $hdir, $prop in map-remove($-zf-flex-justify, 'justify', 'spaced') {
    .align-#{$hdir} {
      &.vertical {
        &.menu > li > a {
          @include flex-align($x: $hdir);
        }
      }
    }
  }

  // Vertical alignment using align-items and align-self
  @each $vdir, $prop in $-zf-flex-align {
    .align-#{$vdir} {
      @include flex-align($y: $vdir);
    }

    .align-self-#{$vdir} {
      @include flex-align-self($y: $vdir);
    }
  }

  // Central alignment of content
  .align-center-middle {
    @include flex-align($x: center, $y: middle);
    align-content: center;
  }

  // Source ordering
  @include -zf-each-breakpoint {
    @for $i from 1 through $flex-source-ordering-count {
      .#{$-zf-size}-order-#{$i} {
        @include flex-order($i);
      }
    }
  }

  // Vanilla Flexbox Helpers
  @include flex-helpers;
}

@mixin form-element {
  $height: ($input-font-size * unitless-calc($input-line-height)) + (get-side($input-padding, 'top') + get-side($input-padding, 'bottom')) - rem-calc(1);

  display: block;
  box-sizing: border-box;
  width: 100%;
  height: $height;
  margin: 0 0 $form-spacing;
  padding: $input-padding;

  border: $input-border;
  border-radius: $input-radius;
  background-color: $input-background;
  box-shadow: $input-shadow;

  font-family: $input-font-family;
  font-size: $input-font-size;
  font-weight: $input-font-weight;
  line-height: $input-line-height;
  color: $input-color;

  @if has-value($input-transition) {
    transition: $input-transition;
  }

  // Focus state
  &:focus {
    outline: none;
    border: $input-border-focus;
    background-color: $input-background-focus;
    box-shadow: $input-shadow-focus;

    @if has-value($input-transition) {
      transition: $input-transition;
    }
  }
}

@mixin foundation-xy-grid-classes(
  $base-grid: true,
  $margin-grid: true,
  $padding-grid: true,
  $block-grid: true,
  $collapse: true,
  $offset: true,
  $vertical-grid: true,
  $frame-grid: true
) {

  // Base grid styles
  @if($base-grid) {
    @include xy-base-grid-classes();
  }

  // Margin grid
  @if($margin-grid) {
    @include xy-margin-grid-classes();
  }

  // Padding grid
  @if($padding-grid) {
    @include xy-padding-grid-classes();
  }

  // Block grid
  @if($block-grid) {
    @include xy-block-grid-classes($margin-grid, $padding-grid);
  }

  // Collapse gutters
  @if($collapse) {
    @include xy-collapse-grid-classes($margin-grid, $padding-grid);
  }

  // Offset gutters
  @if($offset) {
    @include xy-offset-cell-classes();
  }

  // Vertical grid
  @if($vertical-grid) {
    @include xy-vertical-grid-classes($margin-grid, $padding-grid);
  }

  @if ($frame-grid) {
    @include xy-frame-grid-classes($vertical-grid, $margin-grid)
  }
}

@mixin breadcrumbs-container {
  margin: $breadcrumbs-margin;
  list-style: none;

  @include clearfix;

  // Item wrapper
  li {
    float: #{$global-left};

    font-size: $breadcrumbs-item-font-size;
    color: $breadcrumbs-item-color-current;
    cursor: default;

    @if $breadcrumbs-item-uppercase {
      text-transform: uppercase;
    }

    @if $breadcrumbs-item-separator {
      // Need to escape the backslash
      $separator: if($global-text-direction == 'ltr', $breadcrumbs-item-separator-item, $breadcrumbs-item-separator-item-rtl);

      &:not(:last-child) {
        &::after {
          position: relative;
          margin: 0 $breadcrumbs-item-margin;
          opacity: 1;
          content: $separator;
          color: $breadcrumbs-item-separator-color;
        }
      }
    }
    @else {
      margin-#{$global-right}: $breadcrumbs-item-margin;
    }
  }

  // Page links
  a {
    color: $breadcrumbs-item-color;

    &:hover {
      text-decoration: underline;
    }
  }
}

@mixin foundation-prototype-overflow {
  @each $overflow in $prototype-overflow {
    .overflow-#{$overflow} {
      @include overflow($overflow);
    }
    .overflow-x-#{$overflow} {
      @include overflow-x($overflow);
    }
    .overflow-y-#{$overflow} {
      @include overflow-y($overflow);
    }
  }

  @if ($prototype-overflow-breakpoints) {
    // Loop through Responsive Breakpoints
    @each $size in $breakpoint-classes {
      @include breakpoint($size) {
        @each $overflow in $prototype-overflow {
          @if $size != $-zf-zero-breakpoint {
            .#{$size}-overflow-#{$overflow} {
              @include overflow($overflow);
            }
            .#{$size}-overflow-x-#{$overflow} {
              @include overflow-x($overflow);
            }
            .#{$size}-overflow-y-#{$overflow} {
              @include overflow-y($overflow);
            }
          }
        }
      }
    }
  }
}

@mixin foundation-prototype-position {
  // Position: Static, Relative, Fixed, Absolute
  @each $position in $prototype-position {
    .position-#{$position} {
      @include position($position);
    }
  }

  // Position: Fixed Top, Fixed Bottom
  .position-fixed-top {
    @include position-fixed-top;
  }
  .position-fixed-bottom {
    @include position-fixed-bottom;
  }

  @if ($prototype-position-breakpoints) {
    // Loop through Responsive Breakpoints
    @each $size in $breakpoint-classes {
      @include breakpoint($size) {
        // Position: Static, Relative, Fixed, Absolute
        @each $position in $prototype-position {
          @if $size != $-zf-zero-breakpoint {
            .#{$size}-position-#{$position} {
              @include position($position);
            }
          }
        }

        // Position: Fixed Top, Fixed Bottom
        @if $size != $-zf-zero-breakpoint {
          .#{$size}-position-fixed-top {
            @include position-fixed-top;
          }

          .#{$size}-position-fixed-bottom {
            @include position-fixed-bottom;
          }
        }
      }
    }
  }
}

@mixin xy-block-grid-classes($margin-grid: true, $padding-grid: true) {
  @if $padding-grid {
    @include -zf-each-breakpoint {
      @for $i from 1 through $xy-block-grid-max {
        .#{$-zf-size}-up-#{$i} {
          @include xy-grid-layout($n: $i, $selector: '.cell', $gutter-type: padding, $output: (size));
        }
      }
    }
  }

  @if $margin-grid {
    @include -zf-each-breakpoint {
      @for $i from 1 through $xy-block-grid-max {
        // This is purely for responsive gutters - the margin grid has to go back and adjust widths (or heights)
        // for prior breakpoints based on the responsive gutter.
        @if(type-of($grid-margin-gutters) == 'map' and map-has-key($grid-margin-gutters, $-zf-size)) {
          @each $bp in -zf-breakpoints-less-than($-zf-size) {
            @if(map-has-key($grid-margin-gutters, $bp)) {
              .grid-margin-x.#{$bp}-up-#{$i} {
                @include xy-grid-layout($n: $i, $selector: '.cell', $gutter-type: margin, $output: (size));
              }
            }
          }
        }
      }
      @for $i from 1 through $xy-block-grid-max {
        .grid-margin-x.#{$-zf-size}-up-#{$i} {
          @include xy-grid-layout($n: $i, $selector: '.cell', $gutter-type: margin, $output: (size));
        }
      }
    }
  }
}

@if ($gutter-type == 'margin') {

  @include breakpoint($min-breakpoint) {
    @each $value in $gutter-position {
      margin-#{$value}: 0;
    }

    > #{$selector} {
      @each $value in $gutter-position {
        margin-#{$value}: 0;
      }
    }
  }

  $excluded-bps: -zf-breakpoints-less-than($min-breakpoint);

  // Output new widths to not include gutters
  @each $bp in $breakpoint-classes {
    @if(sl-contain($excluded-bps, $bp)) {
      @include breakpoint($min-breakpoint) {
        @for $i from 1 through $grid-columns {
          // Sizing (percentage)
          > .#{$bp}-#{$i} {
            @include xy-cell-size($i, $gutter-type: none);
          }
        }
      }
    } @else {
      @include breakpoint($bp) {
        @for $i from 1 through $grid-columns {
          // Sizing (percentage)
          > .#{$bp}-#{$i} {
            @include xy-cell-size($i, $gutter-type: none);
          }
        }
      }
    }
  }
}

@mixin control {
  align-items: center;
  appearance: none;
  border-color: transparent;
  border-style: solid;
  border-width: cv.getVar("control-border-width");
  border-radius: cv.getVar("control-radius");
  box-shadow: none;
  display: inline-flex;
  font-size: cv.getVar("control-size");
  height: cv.getVar("control-height");
  justify-content: flex-start;
  line-height: cv.getVar("control-line-height");
  padding-bottom: cv.getVar("control-padding-vertical");
  padding-left: cv.getVar("control-padding-horizontal");
  padding-right: cv.getVar("control-padding-horizontal");
  padding-top: cv.getVar("control-padding-vertical");
  position: relative;
  transition-duration: cv.getVar("duration");
  transition-property: background-color, border-color, box-shadow, color;
  vertical-align: top;

  // States
  &:focus,
  &:focus-visible,
  &:focus-within,
  &.#{iv.$class-prefix}is-focused,
  &:active,
  &.#{iv.$class-prefix}is-active {
    outline: none;
  }

  &[disabled],
  fieldset[disabled] & {
    cursor: not-allowed;
  }
}

@mixin off-canvas-base(
  $background: $offcanvas-background,
  $transition: $offcanvas-transition-length $offcanvas-transition-timing,
  $fixed: true
) {
  // Set the off-canvas z-index.
  z-index: $offcanvas-push-zindex;
  transition: transform $transition;
  backface-visibility: hidden;
  background: $background;

  @if $fixed == true {
    position: fixed;
  }
  @else {
    position: absolute;
  }

  @include disable-mouse-outline;

  // Increase CSS specificity
  &.is-transition-push {
    z-index: $offcanvas-push-zindex;
  }

  // Hide inactive off-canvas within the content that have the same position
  &.is-closed {
    visibility: hidden;
  }

  // Overlap only styles.
  &.is-transition-overlap {
    z-index: $offcanvas-overlap-zindex;

    &.is-open {
      box-shadow: $offcanvas-shadow;
    }
  }

  // Sets transform to 0 to show an off-canvas panel.
  &.is-open {
    transform: translate(0, 0);
  }
}

@mixin foundation-switch {
  // Container class
  .switch {
    @include switch-container;
    height: $switch-height;
  }

  // <input> element
  .switch-input {
    @include switch-input;
  }

  // <label> element
  .switch-paddle {
    @include switch-paddle;
  }

  // Base label text styles
  %switch-text {
    @include switch-text;
  }

  // Active label text styles
  .switch-active {
    @extend %switch-text;
    @include switch-text-active;
  }

  // Inactive label text styles
  .switch-inactive {
    @extend %switch-text;
    @include switch-text-inactive;
  }

  // Switch sizes
  .switch.tiny {
    @include switch-size(rem-calc(10), $switch-height-tiny, $switch-paddle-offset);
  }

  .switch.small {
    @include switch-size(rem-calc(12), $switch-height-small, $switch-paddle-offset);
  }

  .switch.large {
    @include switch-size(rem-calc(16), $switch-height-large, $switch-paddle-offset);
  }
}

table {
  display: block;
  width: 100%; // keep for backwards compatibility
  width: max-content;
  max-width: 100%;
  overflow: auto;
  font-variant: tabular-nums;

  th {
    // stylelint-disable-next-line primer/typography
    font-weight: $font-weight-bold;
  }

  th,
  td {
    // stylelint-disable-next-line primer/spacing
    padding: 6px 13px;
    // stylelint-disable-next-line primer/borders, primer/colors
    border: $border-width $border-style var(--borderColor-default, var(--color-border-default));
  }

  td {
    > :last-child {
      margin-bottom: 0;
    }
  }

  tr {
    background-color: var(--bgColor-default, var(--color-canvas-default));
    // stylelint-disable-next-line primer/borders, primer/colors
    border-top: $border-width $border-style var(--borderColor-muted, var(--color-border-muted));

    &:nth-child(2n) {
      background-color: var(--bgColor-muted, var(--color-canvas-subtle));
    }
  }

  img {
    background-color: transparent;
  }
}

@if $enable-container-classes {
  // Single container class with breakpoint max-widths
  .container,
  // 100% wide container at all breakpoints
  .container-fluid {
    @include make-container();
  }

  // Responsive containers that are 100% wide until a breakpoint
  @each $breakpoint, $container-max-width in $container-max-widths {
    .container-#{$breakpoint} {
      @extend .container-fluid;
    }

    @include media-breakpoint-up($breakpoint, $grid-breakpoints) {
      %responsive-container-#{$breakpoint} {
        max-width: $container-max-width;
      }

      // Extend each breakpoint which is smaller or equal to the current breakpoint
      $extend-breakpoint: true;

      @each $name, $width in $grid-breakpoints {
        @if ($extend-breakpoint) {
          .container#{breakpoint-infix($name, $grid-breakpoints)} {
            @extend %responsive-container-#{$breakpoint};
          }

          // Once the current breakpoint is reached, stop extending
          @if ($breakpoint == $name) {
            $extend-breakpoint: false;
          }
        }
      }
    }
  }
}

@function bulmaEnoughContrast($foreground, $background) {
  $r: (
      max(
        color.channel($foreground, "red", $space: rgb),
        color.channel($background, "red", $space: rgb)
      )
    ) -
    (
      min(
        color.channel($foreground, "red", $space: rgb),
        color.channel($background, "red", $space: rgb)
      )
    );
  $g: (
      max(
        color.channel($foreground, "green", $space: rgb),
        color.channel($background, "green", $space: rgb)
      )
    ) -
    (
      min(
        color.channel($foreground, "green", $space: rgb),
        color.channel($background, "green", $space: rgb)
      )
    );
  $b: (
      max(
        color.channel($foreground, "blue", $space: rgb),
        color.channel($background, "blue", $space: rgb)
      )
    ) -
    (
      min(
        color.channel($foreground, "blue", $space: rgb),
        color.channel($background, "blue", $space: rgb)
      )
    );
  $sum-rgb: $r + $g + $b;

  @if $sum-rgb < 500 {
    @return false;
  }

  @return true;
}

a,
  span,
  em {
    min-width: 32px;
    // stylelint-disable-next-line primer/spacing
    padding: 5px 10px;
    font-style: normal;
    // stylelint-disable-next-line primer/typography
    line-height: 20px;
    color: var(--fgColor-default, var(--color-fg-default));
    text-align: center;
    white-space: nowrap;
    vertical-align: middle;
    cursor: pointer;
    user-select: none;
    // stylelint-disable-next-line primer/borders, primer/colors
    border: $border-width $border-style transparent;
    // stylelint-disable-next-line primer/borders
    border-radius: $border-radius;
    transition: border-color 0.2s cubic-bezier(0.3, 0, 0.5, 1);

    &:hover,
    &:focus {
      text-decoration: none;
      border-color: var(--borderColor-default, var(--color-border-default));
      transition-duration: 0.1s;
    }

    &:active {
      border-color: var(--borderColor-muted, var(--color-border-muted));
      transition: none;
    }
  }

@mixin hook-inverse-component-breadcrumb(){

    .uk-breadcrumb > * > * {
        color: $inverse-breadcrumb-item-color;
        @if(meta.mixin-exists(hook-inverse-breadcrumb-item)) {@include hook-inverse-breadcrumb-item();}
    }

    .uk-breadcrumb > * > :hover {
        color: $inverse-breadcrumb-item-hover-color;
        @if(meta.mixin-exists(hook-inverse-breadcrumb-item-hover)) {@include hook-inverse-breadcrumb-item-hover();}
    }


    .uk-breadcrumb > .uk-disabled > * {
        @if(meta.mixin-exists(hook-inverse-breadcrumb-item-disabled)) {@include hook-inverse-breadcrumb-item-disabled();}
    }

    .uk-breadcrumb > :last-child > * {
        color: $inverse-breadcrumb-item-active-color;
        @if(meta.mixin-exists(hook-inverse-breadcrumb-item-active)) {@include hook-inverse-breadcrumb-item-active();}
    }

    //
    // Divider
    //

    .uk-breadcrumb > :nth-child(n+2):not(.uk-first-column)::before {
        color: $inverse-breadcrumb-divider-color;
        @if(meta.mixin-exists(hook-inverse-breadcrumb-divider)) {@include hook-inverse-breadcrumb-divider();}
    }

}

> .card {
  flex: 1 0 0;
  margin-bottom: 0;

  + .card {
    margin-left: 0;
    border-left: 0;
  }

  // Handle rounded corners
  @if $enable-rounded {
    &:not(:last-child) {
      @include border-end-radius(0);

      > .card-img-top,
      > .card-header {
        // stylelint-disable-next-line property-disallowed-list
        border-top-right-radius: 0;
      }
      > .card-img-bottom,
      > .card-footer {
        // stylelint-disable-next-line property-disallowed-list
        border-bottom-right-radius: 0;
      }
    }

    &:not(:first-child) {
      @include border-start-radius(0);

      > .card-img-top,
      > .card-header {
        // stylelint-disable-next-line property-disallowed-list
        border-top-left-radius: 0;
      }
      > .card-img-bottom,
      > .card-footer {
        // stylelint-disable-next-line property-disallowed-list
        border-bottom-left-radius: 0;
      }
    }
  }
}
